import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class XssSecureCode {
    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        PrintWriter out = new PrintWriter("index.html");
        out.println("<html>");
        out.println("<head><title>XSS Secure Example</title></head>");
        out.println("<body>");

        // Sanitize and encode the user input before inserting it into the HTML response
        out.println("<h1>Welcome " + Encode.forHtml(userInput) + "</h1>");

        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
